+impl LogLevel {
+    fn from_env() -> Self {
+        match std::env::var("HARNESS_LOG_LEVEL")
+            .unwrap_or_default()
+            .to_lowercase()
+            .as_str()
+        {
+            "debug" => Self::Debug,
+            "warn" => Self::Warn,
+            "error" => Self::Error,
+            _ => Self::Info,
+        }
+    }
+
+    const fn should_log(self, min_level: Self) -> bool {
+        (self as u8) >= (min_level as u8)
+    }
